/**
 * GridStack.js - Lightweight grid layout engine
 * Minified version for production
 */

window.GridStack = window.GridStack || (function() {
  'use strict';

  const GridStack = function(selector, options) {
    this.container = typeof selector === 'string' ? document.querySelector(selector) : selector;
    this.options = Object.assign({
      cellHeight: 100,
      columns: 12,
      margin: 10,
      staticGrid: false,
      animate: true,
      float: false,
      resizable: true,
      draggable: true
    }, options || {});
    this.items = [];
    this.init();
  };

  GridStack.prototype.init = function() {
    if (!this.container) return;
    this.container.classList.add('grid-stack');
    this.container.setAttribute('data-gs-width', this.options.columns);
    this.setupItems();
    this.bindEvents();
  };

  GridStack.prototype.setupItems = function() {
    const items = this.container.querySelectorAll('.grid-stack-item');
    items.forEach((item, index) => {
      const gs = item.gridstackNode = {
        x: parseInt(item.getAttribute('data-gs-x') || 0),
        y: parseInt(item.getAttribute('data-gs-y') || 0),
        w: parseInt(item.getAttribute('data-gs-w') || 1),
        h: parseInt(item.getAttribute('data-gs-h') || 1),
        element: item
      };
      this.items.push(gs);
      this.updateItemPosition(gs);
    });
  };

  GridStack.prototype.bindEvents = function() {
    if (!this.options.draggable) return;
    this.container.addEventListener('mousedown', (e) => this.onDragStart(e));
    document.addEventListener('mousemove', (e) => this.onDrag(e));
    document.addEventListener('mouseup', (e) => this.onDragEnd(e));
  };

  GridStack.prototype.onDragStart = function(e) {
    const item = e.target.closest('.grid-stack-item');
    if (!item) return;
    this.draggedNode = item.gridstackNode;
    this.dragOffset = { x: e.clientX, y: e.clientY };
    item.classList.add('ui-draggable-dragging');
  };

  GridStack.prototype.onDrag = function(e) {
    if (!this.draggedNode) return;
    const dx = e.clientX - this.dragOffset.x;
    const dy = e.clientY - this.dragOffset.y;
    this.draggedNode.element.style.transform = `translate(${dx}px, ${dy}px)`;
  };

  GridStack.prototype.onDragEnd = function(e) {
    if (!this.draggedNode) return;
    this.draggedNode.element.style.transform = '';
    this.draggedNode.element.classList.remove('ui-draggable-dragging');
    this.draggedNode = null;
  };

  GridStack.prototype.updateItemPosition = function(gs) {
    const { x, y, w, h, element } = gs;
    element.setAttribute('data-gs-x', x);
    element.setAttribute('data-gs-y', y);
    element.setAttribute('data-gs-w', w);
    element.setAttribute('data-gs-h', h);
  };

  GridStack.prototype.getSerializedData = function() {
    return this.items.map(item => ({
      x: item.x,
      y: item.y,
      w: item.w,
      h: item.h,
      id: item.element.getAttribute('data-gs-id')
    }));
  };

  return GridStack;
})();
